import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String inputName = scanner.nextLine();

        // Creating a fixed-size buffer to store the user input
        char[] buffer = new char[10];

        // Copying the user input into the fixed-size buffer with bounds checking
        for (int i = 0; i < Math.min(inputName.length(), buffer.length); i++) {
            buffer[i] = inputName.charAt(i);
        }

        System.out.println("Input successfully stored in secure buffer.");
    }
}

